  dnaAssistantTitle: { en: 'DNA IMPORT ASSISTANT', fr: 'ASSISTANT D’IMPORT ADN', es: 'ASISTENTE DE IMPORTACIÓN DE ADN', pt: 'ASSISTENTE DE IMPORTAÇÃO DE DNA', de: 'DNA-IMPORTASSISTENT', it: 'ASSISTENTE IMPORTAZIONE DNA', ar: 'مساعد استيراد الحمض النووي', zh: 'DNA 导入助手', ja: 'DNAインポートアシスタント', ko: 'DNA 가져오기 도우미', ru: 'ПОМОЩНИК ИМПОРТА ДНК', hi: 'DNA आयात सहायक', sw: 'MSAIDIZI WA KUINGIZA DNA', nl: 'DNA-IMPORTASSISTENT' },
  dnaAssistantDesc: { en: 'Import an ethnicity estimate exported by your DNA provider. The assistant detects regions and percentages for your review.', fr: 'Importez une estimation ethnique exportée par votre laboratoire ADN. L’assistant détecte les régions et pourcentages pour validation.', es: 'Importa una estimación étnica exportada por tu proveedor de ADN. El asistente detecta regiones y porcentajes para revisarlos.', pt: 'Importe uma estimativa étnica exportada pelo seu fornecedor de DNA. O assistente detecta regiões e percentuais para revisão.', de: 'Importiere eine Herkunftsschätzung deines DNA-Anbieters. Der Assistent erkennt Regionen und Anteile zur Prüfung.', it: 'Importa una stima etnica del tuo fornitore DNA. L’assistente rileva regioni e percentuali da verificare.', ar: 'استورد تقدير الأصول من مزود فحص الحمض النووي. يكتشف المساعد المناطق والنسب لمراجعتها.', zh: '导入 DNA 服务商提供的族群估算。助手会识别地区和百分比供你确认。', ja: 'DNAサービスから出力した民族推定を読み込みます。地域と割合を検出し、確認できます。', ko: 'DNA 제공업체의 민족 추정 결과를 가져옵니다. 지역과 비율을 감지하여 검토할 수 있습니다.', ru: 'Импортируйте оценку происхождения от DNA-сервиса. Помощник распознает регионы и проценты для проверки.', hi: 'अपने DNA प्रदाता से निर्यातित जातीयता अनुमान आयात करें। सहायक समीक्षा के लिए क्षेत्र और प्रतिशत पहचानता है।', sw: 'Ingiza makadirio ya asili kutoka kwa mtoa huduma wa DNA. Msaidizi hutambua maeneo na asilimia kwa ukaguzi.', nl: 'Importeer een afkomstschatting van je DNA-aanbieder. De assistent herkent regio’s en percentages ter controle.' },
  dnaUploadBtn: { en: 'UPLOAD CSV, TXT OR JSON', fr: 'IMPORTER CSV, TXT OU JSON', es: 'SUBIR CSV, TXT O JSON', pt: 'ENVIAR CSV, TXT OU JSON', de: 'CSV, TXT ODER JSON HOCHLADEN', it: 'CARICA CSV, TXT O JSON', ar: 'رفع CSV أو TXT أو JSON', zh: '上传 CSV、TXT 或 JSON', ja: 'CSV・TXT・JSONをアップロード', ko: 'CSV, TXT 또는 JSON 업로드', ru: 'ЗАГРУЗИТЬ CSV, TXT ИЛИ JSON', hi: 'CSV, TXT या JSON अपलोड करें', sw: 'PAKIA CSV, TXT AU JSON', nl: 'CSV, TXT OF JSON UPLOADEN' },
  dnaAnalyzing: { en: 'ANALYZING LOCALLY…', fr: 'ANALYSE LOCALE…', es: 'ANALIZANDO LOCALMENTE…', pt: 'ANALISANDO LOCALMENTE…', de: 'LOKALE ANALYSE…', it: 'ANALISI LOCALE…', ar: 'جارٍ التحليل محلياً…', zh: '正在本地分析…', ja: '端末内で分析中…', ko: '기기에서 분석 중…', ru: 'ЛОКАЛЬНЫЙ АНАЛИЗ…', hi: 'स्थानीय विश्लेषण…', sw: 'INACHAMBUA KWENYE KIFAA…', nl: 'LOKAAL ANALYSEREN…' },
  dnaLocalPrivacy: { en: 'Private local analysis · file not uploaded', fr: 'Analyse privée sur votre appareil · fichier non envoyé', es: 'Análisis privado local · archivo no enviado', pt: 'Análise privada local · arquivo não enviado', de: 'Private lokale Analyse · Datei wird nicht gesendet', it: 'Analisi privata locale · file non inviato', ar: 'تحليل محلي خاص · لا يتم إرسال الملف', zh: '本地私密分析 · 文件不会上传', ja: '端末内の非公開分析 · ファイルは送信されません', ko: '비공개 로컬 분석 · 파일은 전송되지 않음', ru: 'Приватный локальный анализ · файл не отправляется', hi: 'निजी स्थानीय विश्लेषण · फ़ाइल अपलोड नहीं होती', sw: 'Uchambuzi wa faragha kwenye kifaa · faili haitumwi', nl: 'Privé lokaal geanalyseerd · bestand wordt niet verzonden' },
